from flask import Flask, request, jsonify, abort
from flask_sqlalchemy import SQLAlchemy
import os
import uuid
from itsdangerous import TimedJSONWebSignatureSerializer as Serializer

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(80), nullable=False, unique=True)
    reset_token = db.Column(db.String(128))

    def set_reset_password_token(self, token):
        self.reset_token = token

    def is_authenticated(self):
        return True

    def is_active(self):
        return True

    def get_id(self):
        return str(self.id)

@app.route('/api/password_reset', methods=['POST'])
def password_reset():
    if not request.is_json:
        abort(400)

    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()

    if not user:
        abort(404, description="User not found.")

    token = str(uuid.uuid4())
    user.set_reset_password_token(token)
    db.session.commit()

    s = Serializer(app.config['SECRET_KEY'], expires_in=3600)
    reset_url = url_for('reset_password', token=s.dumps(user.id).decode(), _external=True)

    msg = Message("Password Reset Request", sender='noreply@yourdomain.com', recipients=[email])
    msg.html = f"""
        <p>Please use the following link to reset your password:</p>
        <a href="{reset_url}">Reset Password</a>
    """
    mail.send(msg)

    return jsonify({"message": "Email has been sent"})

@app.route('/api/password_reset/<token>', methods=['GET'])
def reset_password(token):
    s = Serializer(app.config['SECRET_KEY'], expires_in=3600)
    try:
        user_id = s.loads(token, salt='my-salt-here')
        user = User.query.get(user_id)
        if not user or not user.reset_password_token:
            abort(403, description="Invalid token.")

        return jsonify({"message": "Use this token to reset your password."})
    except BadSignature:
        abort(403, description="Invalid token.")